module SR_latch (input S, input R, output reg obf_Q, output Qn);  
    always @(S, R) begin  
        if (S && !R)  
            obf_Q <= 1;  
        else if (!S && R)  
            obf_Q <= 0;  
        // If both S and R are low, retain previous state  
    end  
    assign Qn = ~obf_Q;  
endmodule
